**Idea:**

We first build the graph using an adjacency list. Using an iterative Graph Traversal method (such as BFS or DFS), we explore the graph and compute the sum of museums for each connected component. Once we have these sums, we sort them and simulate the KKK trips as follows:


For odd-numbered trips (e.g., month 1, 3, 5, …), Lavanya picks the connected component with the maximum museum count (i.e. the last element from the sorted list).
For even-numbered trips, Nikhil picks the component with the minimum museum count (i.e. the first element from the sorted list).
**Simulation Details:**

Let the sorted list (in ascending order) be LLL. Initialize two pointers: one at the beginning (for the minimum elements) and one at the end (for the maximum elements). Then iterate for KKK months:


On month iii (using 0-indexing):

If iii is even, add L[right]L[\text{right}]L[right] (maximum), then decrement the right pointer.
If iii is odd, add L[left]L[\text{left}]L[left] (minimum), then increment the left pointer.


If the total number of connected components is less than KKK, then we output −1-1−1.

The following code implementations in C++ and Python demonstrate this approach.

**C++ Code Implementation for Approach 1:**

`#include &lt;iostream&gt;
#include &lt;vector&gt;
#include &lt;queue&gt;
#include &lt;algorithm&gt;
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int T;
    cin &gt;&gt; T;
    while(T--){
        int N, M, K;
        cin &gt;&gt; N &gt;&gt; M &gt;&gt; K;
        vector&lt;vector&lt;int&gt;&gt; graph(N+1);
        for(int i = 0; i &lt; M; i++){
            int u, v;
            cin &gt;&gt; u &gt;&gt; v;
            graph[u].push_back(v);
            graph[v].push_back(u);
        }
        vector&lt;int&gt; museums(N+1);
        for(int i = 1; i &lt;= N; i++){
            cin &gt;&gt; museums[i];
        }

        vector&lt;bool&gt; visited(N+1, false);
        vector&lt;long long&gt; compSums;

        for(int i = 1; i &lt;= N; i++){
            if(!visited[i]){
                long long sum = 0;
                queue&lt;int&gt; q;
                q.push(i);
                visited[i] = true;
                while(!q.empty()){
                    int cur = q.front();
                    q.pop();
                    sum += museums[cur];
                    for(auto nbr: graph[cur]){
                        if(!visited[nbr]){
                            visited[nbr] = true;
                            q.push(nbr);
                        }
                    }
                }
                compSums.push_back(sum);
            }
        }

        if(compSums.size() &lt; (size_t)K){
            cout &lt;&lt; -1 &lt;&lt; "\n";
            continue;
        }

        sort(compSums.begin(), compSums.end());
        int left = 0, right = compSums.size()-1;
        long long total = 0;
        for(int i = 0; i &lt; K; i++){
            if(i % 2 == 0){ // Lavanya's turn, pick maximum
                total += compSums[right];
                right--;
            } else { // Nikhil's turn, pick minimum
                total += compSums[left];
                left++;
            }
        }
        cout &lt;&lt; total &lt;&lt; "\n";
    }
    return 0;
}
`**Python Code Implementation for Approach 1:**

`from collections import deque
import sys
input = sys.stdin.readline

T = int(input().strip())
for _ in range(T):
    N, M, K = map(int, input().split())
    graph = [[] for _ in range(N+1)]
    for _ in range(M):
        u, v = map(int, input().split())
        graph[u].append(v)
        graph[v].append(u)
    museums = [0] + list(map(int, input().split()))

    visited = [False]*(N+1)
    compSums = []

    for i in range(1, N+1):
        if not visited[i]:
            q = deque([i])
            visited[i] = True
            comp_sum = 0
            while q:
                cur = q.popleft()
                comp_sum += museums[cur]
                for nbr in graph[cur]:
                    if not visited[nbr]:
                        visited[nbr] = True
                        q.append(nbr)
            compSums.append(comp_sum)

    if len(compSums) &lt; K:
        print(-1)
        continue

    compSums.sort()
    left, right = 0, len(compSums)-1
    total = 0
    for i in range(K):
        if i % 2 == 0:  # Lavanya's turn
            total += compSums[right]
            right -= 1
        else:  # Nikhil's turn
            total += compSums[left]
            left += 1
    print(total)
`
